196→fn is_ignored_dir(name: &str) -> bool {
197→    matches!(
198→        name,
199→        ".git"
200→            | "node_modules"
201→            | "__pycache__"
202→            | ".next"
203→            | ".cache"
204→            | ".vscode"
205→            | ".idea"
206→            | "target"
207→            | "dist"
208→            | "build"
209→            | ".Trash"
210→    )
211→}
