213→fn is_path_within_home(path: &std::path::Path) -> bool {
214→    let canonical = match path.canonicalize() {
215→        Ok(p) => p,
216→        Err(_) => return false,
217→    };
218→    if let Some(home) = dirs_next::home_dir() {
219→        return canonical.starts_with(&home);
220→    }
221→    false
222→}
