224→#[tauri::command(async)]
225→fn search_files(query: String, paths: Vec<String>, max_results: usize) -> Vec<FileEntryResult> {
226→    let max = if max_results == 0 { 200 } else { max_results };
227→    let query_lower = query.to_lowercase();
228→    let mut results: Vec<FileEntryResult> = Vec::new();
229→
230→    let search_paths: Vec<String> = if paths.is_empty() {
231→        if let Some(home) = dirs_next::home_dir() {
232→            let home_str = home.to_string_lossy().to_string();
233→            vec![
234→                format!("{home_str}/Documents"),
235→                format!("{home_str}/Downloads"),
236→                format!("{home_str}/Desktop"),
237→                format!("{home_str}/Projects"),
238→            ]
239→        } else {
240→            return results;
241→        }
242→    } else {
243→        paths
244→    };
245→
246→    for search_path in &search_paths {
247→        if results.len() >= max {
248→            break;
249→        }
250→
251→        let walker = WalkDir::new(search_path)
252→            .max_depth(5)
253→            .follow_links(false)
254→            .into_iter()
255→            .filter_entry(|entry| {
256→                let name = entry.file_name().to_string_lossy();
257→                if name.starts_with('.') && entry.depth() > 0 {
258→                    return false;
259→                }
260→                if entry.file_type().is_dir() && is_ignored_dir(&name) {
261→                    return false;
262→                }
263→                true
264→            });
265→
266→        for entry in walker.flatten() {
267→            if results.len() >= max {
268→                break;
269→            }
270→
271→            let name = entry.file_name().to_string_lossy().to_string();
272→
273→            if !query_lower.is_empty() && !name.to_lowercase().contains(&query_lower) {
274→                continue;
275→            }
276→
277→            if entry.depth() == 0 {
278→                continue;
279→            }
280→
281→            let path = entry.path();
282→            let metadata = match entry.metadata() {
283→                Ok(m) => m,
284→                Err(_) => continue,
285→            };
286→
287→            let size = metadata.len();
288→            let modified_at = metadata
289→                .modified()
290→                .ok()
291→                .and_then(|t| t.duration_since(std::time::UNIX_EPOCH).ok())
292→                .map(|d| d.as_millis() as u64)
293→                .unwrap_or(0);
294→
295→            let file_type = detect_file_type(path);
296→            let path_str = path.to_string_lossy().to_string();
297→
298→            let id = format!("fs-{:x}", {
299→                use std::hash::{Hash, Hasher};
300→                let mut h = std::collections::hash_map::DefaultHasher::new();
301→                path_str.hash(&mut h);
302→                h.finish()
303→            });
304→
305→            results.push(FileEntryResult {
306→                id,
307→                name,
308→                path: path_str,
309→                file_type: file_type.to_string(),
310→                size,
311→                modified_at,
312→            });
313→        }
314→    }
315→
316→    results
317→}
