392→#[tauri::command]
393→fn set_window_position_pref(
394→    state: tauri::State<'_, Mutex<WindowConfig>>,
395→    position: String,
396→) -> Result<(), String> {
397→    match position.as_str() {
398→        "center" | "top-third" => {
