411→pub fn run() {
412→    tauri::Builder::default()
413→        .plugin(tauri_plugin_clipboard_manager::init())
414→        .plugin(tauri_plugin_shell::init())
415→        .manage(Mutex::new(WindowConfig::default()))
416→        .invoke_handler(tauri::generate_handler![
417→            set_window_position_pref,
418→            search_files,
419→            open_file,
420→            reveal_in_finder,
421→            move_to_trash
422→        ])
423→        .setup(|app| {
424→            #[cfg(desktop)]
425→            {
426→                let shortcut = Shortcut::new(Some(Modifiers::ALT), Code::Space);
427→                let window = app
428→                    .get_webview_window("main")
429→                    .expect("main window not found");
430→
431→                let window_for_blur = window.clone();
432→                window.on_window_event(move |event| {
433→                    if let tauri::WindowEvent::Focused(false) = event {
434→                        if let Err(e) = window_for_blur.hide() {
435→                            eprintln!("failed to hide on blur: {e}");
436→                        }
437→                    }
438→                });
439→
440→                #[cfg(target_os = "macos")]
441→                {
442→                    use window_vibrancy::{apply_vibrancy, NSVisualEffectMaterial};
443→                    if let Err(e) =
444→                        apply_vibrancy(&window, NSVisualEffectMaterial::HudWindow, None, None)
445→                    {
446→                        eprintln!("failed to apply vibrancy: {e}");
447→                    }
448→                }
449→
450→                position_near_top(&window);
451→
452→                start_clipboard_monitor(app.handle().clone());
453→
454→                let window_for_shortcut = window.clone();
455→                app.handle().plugin(
456→                    tauri_plugin_global_shortcut::Builder::new()
457→                        .with_handler(move |_app, scut, event| {
458→                            if scut == &shortcut && event.state() == ShortcutState::Pressed {
459→                                toggle_window(&window_for_shortcut);
460→                            }
461→                        })
462→                        .build(),
463→                )?;
464→
465→                app.global_shortcut().register(shortcut)?;
466→
467→                let show_item =
468→                    MenuItem::with_id(app, "show", "Show Raycast", true, None::<&str>)?;
469→                let clipboard_item =
470→                    MenuItem::with_id(app, "clipboard", "Clipboard History", true, None::<&str>)?;
471→                let snippets_item =
472→                    MenuItem::with_id(app, "snippets", "Snippets", true, None::<&str>)?;
473→                let settings_item =
474→                    MenuItem::with_id(app, "settings", "Settings", true, None::<&str>)?;
475→                let check_updates_item = MenuItem::with_id(
476→                    app,
477→                    "check-updates",
478→                    "Check for Updates",
479→                    true,
480→                    None::<&str>,
481→                )?;
482→                let about_item =
483→                    MenuItem::with_id(app, "about", "About Raycast Clone", true, None::<&str>)?;
484→                let quit_item = MenuItem::with_id(app, "quit", "Quit", true, None::<&str>)?;
485→
486→                let menu = Menu::with_items(
487→                    app,
488→                    &[
489→                        &show_item,
490→                        &PredefinedMenuItem::separator(app)?,
491→                        &clipboard_item,
492→                        &snippets_item,
493→                        &settings_item,
494→                        &PredefinedMenuItem::separator(app)?,
495→                        &check_updates_item,
496→                        &about_item,
497→                        &quit_item,
498→                    ],
499→                )?;
500→
501→                let window_for_menu = window.clone();
502→                let window_for_tray = window.clone();
503→
504→                TrayIconBuilder::new()
505→                    .icon(tauri::image::Image::from_bytes(include_bytes!(
506→                        "../icons/tray-icon@2x.png"
507→                    ))?)
508→                    .icon_as_template(true)
509→                    .tooltip("Raycast Clone")
510→                    .menu(&menu)
511→                    .show_menu_on_left_click(false)
512→                    .on_menu_event(move |app, event| match event.id().as_ref() {
513→                        "show" => {
514→                            show_and_focus(&window_for_menu);
515→                        }
516→                        "clipboard" | "snippets" | "settings" | "about" | "check-updates" => {
517→                            show_and_focus(&window_for_menu);
518→                            if let Err(e) =
519→                                app.emit("tray-navigate", event.id().as_ref().to_string())
520→                            {
521→                                eprintln!("failed to emit tray-navigate: {e}");
522→                            }
523→                        }
524→                        "quit" => {
525→                            app.exit(0);
526→                        }
527→                        _ => {}
528→                    })
529→                    .on_tray_icon_event(move |_tray, event| {
530→                        if let TrayIconEvent::Click {
531→                            button: MouseButton::Left,
532→                            button_state: MouseButtonState::Up,
533→                            ..
534→                        } = event
535→                        {
536→                            toggle_window(&window_for_tray);
537→                        }
538→                    })
539→                    .build(app)?;
540→            }
541→
542→            Ok(())
543→        })
544→        .run(tauri::generate_context!())
545→        .expect("error while running tauri application");
546→}
