 18→function renderNavView(data: NavViewData) {
 19→  if (data.type === 'command') {
 20→    const cmd = getCommand(data.commandId);
 21→    if (cmd?.component) {
 22→      const Component = cmd.component;
 23→      return <Component />;
 24→    }
 25→    return null;
 26→  }
 27→
 28→  if (data.type === 'detail') {
 29→    return <DetailItemView item={data.item} />;
 30→  }
 31→
 32→  return null;
 33→}
