 35→export function App() {
 36→  useTheme();
 37→  const nav = useNavigationStack<NavViewData>('Raycast');
 38→  const { push, popToRoot } = nav;
 39→  const { addRecent } = useRecentCommands();
 40→  const [isCompact, setIsCompact] = useState(true);
 41→  const [rootResetKey, setRootResetKey] = useState(0);
 42→
 43→  const handleTrayNavigate = useCallback(
 44→    (target: string) => {
 45→      const mapping = TRAY_COMMAND_MAP[target];
 46→      if (!mapping) return;
 47→
 48→      const cmd = getCommand(mapping.id);
 49→      if (!cmd?.component) return;
 50→
 51→      popToRoot();
 52→      addRecent(mapping.id);
 53→      push(mapping.name, {
 54→        type: 'command',
 55→        commandId: mapping.id,
 56→      });
 57→    },
 58→    [
 59→      push,
 60→      popToRoot,
 61→      addRecent,
 62→    ],
 63→  );
 64→
 65→  useWindow({
 66→    onShow: () => {
 67→      const input =
 68→        document.querySelector<HTMLInputElement>('.search-bar__input');
 69→      input?.focus();
 70→    },
 71→    onHide: () => {
 72→      popToRoot();
 73→      setRootResetKey(k => k + 1);
 74→    },
 75→    onTrayNavigate: handleTrayNavigate,
 76→  });
 77→
 78→  const currentNavData = nav.currentEntry?.data;
 79→  const isFullView =
 80→    currentNavData?.type === 'command' &&
 81→    (getCommand(currentNavData.commandId)?.fullView ?? false);
 82→
 83→  const navDirectionClass =
 84→    nav.direction === 'push'
 85→      ? ' command-palette__nav-view--push'
 86→      : nav.direction === 'pop'
 87→        ? ' command-palette__nav-view--pop'
 88→        : '';
 89→
 90→  const isRoot = !currentNavData;
 91→  const compact = isRoot && isCompact;
 92→
 93→  const contextLabel =
 94→    nav.breadcrumbs.length > 0
 95→      ? nav.breadcrumbs[nav.breadcrumbs.length - 1]!.label
 96→      : 'Raycast';
 97→
 98→  return (
 99→    <NavigationContextProvider value={nav}>
100→      <CommandPalette isLoading compact={compact}>
101→        {isFullView && nav.currentEntry ? (
102→          <div
103→            key={nav.navKey}
104→            className={`command-palette__nav-view${navDirectionClass}`}
105→          >
106→            {renderNavView(nav.currentEntry.data)}
107→          </div>
108→        ) : nav.currentEntry ? (
109→          <>
110→            <SearchBar
111→              value=""
112→              onChange={() => {}}
113→              breadcrumbs={
114→                nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined
115→              }
116→            />
117→            <div
118→              key={nav.navKey}
119→              className={`command-palette__nav-view${navDirectionClass}`}
120→            >
121→              <div className="command-palette__body">
122→                <div className="command-palette__list-container">
123→                  {renderNavView(nav.currentEntry.data)}
124→                </div>
125→              </div>
126→            </div>
127→            <ActionPanel
128→              contextLabel={contextLabel}
129→              actions={[
130→                {
131→                  label: 'Open',
132→                  shortcut: <Kbd keys={['↵']} />,
133→                },
134→              ]}
135→              dropdownOpen={false}
136→              dropdownSections={[]}
137→              onDropdownClose={() => {}}
138→            />
139→          </>
140→        ) : (
141→          <RootSearchView key={rootResetKey} onCompactChange={setIsCompact} />
142→        )}
143→      </CommandPalette>
144→    </NavigationContextProvider>
145→  );
146→}
