  1→import type { ListItemData, SectionData } from '../types';
  2→import { fuzzyScore } from '../utils/fuzzy_search';
  3→import type { CommandRegistration, ExtensionManifest } from './types';
  4→
  5→const commands = new Map<string, CommandRegistration>();
  6→
  7→const sectionOrder: string[] = [];
  8→
  9→export function registerCommand(cmd: CommandRegistration): void {
 10→  if (import.meta.env.DEV && commands.has(cmd.id)) {
 11→    console.warn(`Command "${cmd.id}" is already registered. Overwriting.`);
 12→  }
 13→  commands.set(cmd.id, cmd);
 14→  if (!sectionOrder.includes(cmd.section)) {
 15→    sectionOrder.push(cmd.section);
 16→  }
 17→}
 18→
 19→export function registerExtension(manifest: ExtensionManifest): void {
 20→  for (const cmd of manifest.commands) {
 21→    const section = cmd.section ?? manifest.name;
 22→    registerCommand({
 23→      id: cmd.name,
 24→      name: cmd.title,
 25→      subtitle: cmd.subtitle,
 26→      icon: cmd.icon,
 27→      keywords: cmd.keywords,
 28→      aliases: cmd.aliases,
 29→      section,
 30→      accessories: cmd.accessories,
 31→      detail: cmd.detail,
 32→      component: cmd.component,
 33→      fullView: cmd.fullView,
 34→      extensionId: manifest.id,
 35→    });
 36→  }
 37→}
 38→
 39→export function getCommand(id: string): CommandRegistration | undefined {
 40→  return commands.get(id);
 41→}
 42→
 43→function toListItem(cmd: CommandRegistration): ListItemData {
 44→  return {
 45→    id: cmd.id,
 46→    title: cmd.name,
 47→    subtitle: cmd.subtitle,
 48→    icon: cmd.icon,
 49→    accessories: cmd.accessories,
 50→    detail: cmd.detail,
 51→  };
 52→}
 53→
 54→export function getSections(): SectionData[] {
 55→  const grouped = new Map<string, ListItemData[]>();
 56→
 57→  for (const section of sectionOrder) {
 58→    grouped.set(section, []);
 59→  }
 60→
 61→  for (const cmd of commands.values()) {
 62→    let items = grouped.get(cmd.section);
 63→    if (!items) {
 64→      items = [];
 65→      grouped.set(cmd.section, items);
 66→    }
 67→    items.push(toListItem(cmd));
 68→  }
 69→
 70→  const sections: SectionData[] = [];
 71→  for (const [title, items] of grouped) {
 72→    if (items.length > 0) {
 73→      sections.push({
 74→        title,
 75→        items,
 76→      });
 77→    }
 78→  }
 79→  return sections;
 80→}
 81→
 82→interface ScoredItem {
 83→  item: ListItemData;
 84→  score: number;
 85→  section: string;
 86→}
 87→
 88→function scoreItem(item: ListItemData, query: string): number {
 89→  const cmd = commands.get(item.id);
 90→  const candidates: string[] = [item.title];
 91→  if (item.subtitle) candidates.push(item.subtitle);
 92→  if (cmd?.keywords) candidates.push(...cmd.keywords);
 93→  if (cmd?.aliases) candidates.push(...cmd.aliases);
 94→
 95→  let best = -Infinity;
 96→  for (const text of candidates) {
 97→    const result = fuzzyScore(query, text);
 98→    if (result && result.score > best) {
 99→      best = result.score;
100→    }
101→  }
102→  return best;
103→}
104→
105→export function searchCommands(query: string): SectionData[] {
106→  if (!query) return getSections();
107→
108→  const sections = getSections();
109→  const scored: ScoredItem[] = [];
110→
111→  for (const section of sections) {
112→    for (const item of section.items) {
113→      const s = scoreItem(item, query);
114→      if (s > -Infinity) {
115→        scored.push({
116→          item,
117→          score: s,
118→          section: section.title,
119→        });
120→      }
121→    }
122→  }
123→
124→  scored.sort((a, b) => b.score - a.score);
125→
126→  const sectionMap = new Map<string, ListItemData[]>();
127→  for (const { item, section } of scored) {
128→    let items = sectionMap.get(section);
129→    if (!items) {
130→      items = [];
131→      sectionMap.set(section, items);
132→    }
133→    items.push(item);
134→  }
135→
136→  const result: SectionData[] = [];
137→  for (const section of sections) {
138→    const items = sectionMap.get(section.title);
139→    if (items && items.length > 0) {
140→      result.push({
141→        title: section.title,
142→        items,
143→      });
144→    }
145→  }
146→  return result;
147→}
